import React from 'react';
import { Routes, Route, Link, NavLink } from 'react-router-dom';
import Home from './pages/home';
import WorkflowPage from './pages/workflowPage';
import { WorkflowProvider } from './store/workflowContext';
import LoginPage from './pages/login';
import RegisterPage from './pages/register';
import DocumentsPage from './pages/documents';


// import './App.css'; // ⬅️ remove CRA styles so they don’t override Tailwind

function App() {
  return (
    <WorkflowProvider>
      <div className="min-h-screen bg-white text-slate-900">
        {/* Top Nav */}
        <header className="border-b border-slate-200">
          <div className="mx-auto max-w-6xl px-4 py-3 flex items-center justify-between">
            {/* Brand */}
            <Link to="/" className="flex items-center gap-2">
              {/* Simple book mark as logo, replace with your SVG if you have one */}
              <div className="w-6 h-6 rounded-sm bg-slate-900"></div>
              <span className="font-bold tracking-tight">ManuscriptMagic<span className="text-blue-600">.ai</span></span>
            </Link>

            {/* Primary nav */}
            <nav className="hidden md:flex items-center gap-8 text-sm text-slate-600">
              <a href="#how" className="hover:text-slate-900">How It Works</a>
              <a href="#features" className="hover:text-slate-900">Features</a>
              <a href="#pricing" className="hover:text-slate-900">Pricing</a>
              <a href="#support" className="hover:text-slate-900">Support</a>
            </nav>

            {/* Auth / CTA */}
            <div className="flex items-center gap-3">
              <NavLink to="/login" className="text-sm text-slate-600 hover:text-slate-900">Sign In</NavLink>
              <Link
                to="/workflow/start"
                className="text-sm rounded-md px-3 py-2 bg-blue-600 text-white hover:bg-blue-700"
              >
                Get Started
              </Link>
            </div>
          </div>
        </header>

        {/* Routed pages */}
        <main>
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/workflow/*" element={<WorkflowPage />} />
            <Route path="/login" element={<LoginPage />} />
            <Route path="/register" element={<RegisterPage />} />
            <Route path="/documents" element={<DocumentsPage />} />
          </Routes>
        </main>
      </div>
    </WorkflowProvider>
  );
}

export default App;
